// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable. " +
        "Example: export OPENAI_API_KEY=sk-...");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient ---
IChatClient chatClient = new OpenAIClient(new ApiKeyCredential(apiKey))
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Set up tools ---
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
httpClient.Timeout = TimeSpan.FromSeconds(30);

var webSearch = new WebSearchTool(httpClient);
var notes = new NoteTool();

AITool[] tools =
[
    AIFunctionFactory.Create(webSearch.SearchWebAsync),
    AIFunctionFactory.Create(webSearch.FetchWebPageAsync),
    AIFunctionFactory.Create(notes.SaveNote),
    AIFunctionFactory.Create(notes.GetNotes),
];

// --- Create the agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your job is to research a topic thoroughly using the 
        available tools and produce a well-organized summary.

        Follow this workflow:
        1. Use search_web to find relevant pages about the topic.
        2. Use fetch_webpage to read the most promising results (2-3 pages).
        3. Use save_note to record key facts, statistics, and insights with source URLs.
        4. Use get_notes to review everything you've collected.
        5. Write a comprehensive summary organized with clear sections.

        Guidelines:
        - Search multiple angles of the topic for breadth.
        - Always attribute facts to their sources.
        - Be factual and concise — avoid speculation.
        - End with a "Sources" section listing all URLs used.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and summarizing findings.",
    tools: tools);

// --- Get the research topic ---
string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a research topic: ");
    topic = Console.ReadLine()?.Trim() ?? "";
    if (string.IsNullOrEmpty(topic))
    {
        Console.Error.WriteLine("No topic provided. Usage: dotnet run -- \"your research topic\"");
        return;
    }
}

Console.WriteLine();
Console.WriteLine($"🔍 Researching: {topic}");
Console.WriteLine(new string('─', 60));

// --- Run the agent with streaming ---
var runOptions = new ChatClientAgentRunOptions(
    new ChatOptions { Temperature = 0f });

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session: null,
    options: runOptions))
{
    if (!string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine();
Console.WriteLine(new string('─', 60));
Console.WriteLine("✅ Research complete.");

