using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search and page-fetching capabilities for the research agent.
/// </summary>
public sealed partial class WebSearchTool(HttpClient httpClient)
{
    [GeneratedRegex("<[^>]+>")]
    private static partial Regex HtmlTagRegex();

    [GeneratedRegex(@"\s{2,}")]
    private static partial Regex WhitespaceRegex();

    [AIFunction(Name = "search_web")]
    [Description("Searches the web for a query and returns a list of result titles, snippets, and URLs. Use this to discover relevant pages about a topic.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up on the web.")] string query,
        CancellationToken cancellationToken = default)
    {
        try
        {
            // Use DuckDuckGo HTML lite for free, no-auth search
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";

            using var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.Add("Accept", "text/html");

            var response = await httpClient.SendAsync(request, cancellationToken);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync(cancellationToken);
            return ParseSearchResults(html);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query or use fetch_webpage with a known URL.";
        }
    }

    [AIFunction(Name = "fetch_webpage")]
    [Description("Fetches the text content of a webpage given its URL. Use this to read the full content of a page found via search.")]
    public async Task<string> FetchWebPageAsync(
        [Description("The full URL of the webpage to fetch (e.g. https://example.com/article).")] string url,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var response = await httpClient.GetAsync(url, cancellationToken);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync(cancellationToken);
            var text = ExtractTextFromHtml(html);

            const int maxLength = 8000;
            if (text.Length > maxLength)
            {
                text = text[..maxLength] + "\n\n[Content truncated...]";
            }

            return string.IsNullOrWhiteSpace(text)
                ? "Could not extract meaningful text from this page."
                : text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    private static string ParseSearchResults(string html)
    {
        var results = new List<string>();

        // Extract result blocks from DuckDuckGo HTML lite
        var linkMatches = Regex.Matches(html, @"<a[^>]+class=""result__a""[^>]*href=""([^""]*?)""[^>]*>(.*?)</a>", RegexOptions.Singleline);
        var snippetMatches = Regex.Matches(html, @"<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>", RegexOptions.Singleline);

        for (var i = 0; i < Math.Min(linkMatches.Count, 8); i++)
        {
            var title = StripHtml(linkMatches[i].Groups[2].Value).Trim();
            var link = linkMatches[i].Groups[1].Value.Trim();

            // DuckDuckGo wraps URLs in a redirect; extract the actual URL
            var uddgMatch = Regex.Match(link, @"uddg=([^&]+)");
            if (uddgMatch.Success)
            {
                link = Uri.UnescapeDataString(uddgMatch.Groups[1].Value);
            }

            var snippet = i < snippetMatches.Count
                ? StripHtml(snippetMatches[i].Groups[1].Value).Trim()
                : "";

            results.Add($"[{i + 1}] {title}\n    URL: {link}\n    {snippet}");
        }

        return results.Count > 0
            ? string.Join("\n\n", results)
            : "No results found. Try rephrasing your query.";
    }

    private static string ExtractTextFromHtml(string html)
    {
        // Remove script and style blocks
        var cleaned = Regex.Replace(html, @"<(script|style|nav|header|footer)[^>]*>.*?</\1>", "", RegexOptions.Singleline | RegexOptions.IgnoreCase);

        // Decode common entities
        cleaned = cleaned
            .Replace("&amp;", "&")
            .Replace("&lt;", "<")
            .Replace("&gt;", ">")
            .Replace("&quot;", "\"")
            .Replace("&#39;", "'")
            .Replace("&nbsp;", " ");

        // Add line breaks for block elements
        cleaned = Regex.Replace(cleaned, @"<(br|p|div|h[1-6]|li|tr)[^>]*>", "\n", RegexOptions.IgnoreCase);

        // Strip remaining HTML tags
        cleaned = HtmlTagRegex().Replace(cleaned, "");

        // Collapse whitespace
        cleaned = WhitespaceRegex().Replace(cleaned, " ");

        // Collapse multiple newlines
        cleaned = Regex.Replace(cleaned, @"\n{3,}", "\n\n");

        return cleaned.Trim();
    }

    private static string StripHtml(string html)
    {
        var text = html
            .Replace("&amp;", "&")
            .Replace("&lt;", "<")
            .Replace("&gt;", ">")
            .Replace("&quot;", "\"")
            .Replace("&#39;", "'")
            .Replace("<b>", "")
            .Replace("</b>", "");

        return HtmlTagRegex().Replace(text, "");
    }
}

using System.ComponentModel;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capabilities for the research agent to collect and organize findings.
/// </summary>
public sealed class NoteTool
{
    private readonly List<Note> _notes = [];

    [AIFunction(Name = "save_note")]
    [Description("Saves a research note with a title and content. Use this to record key findings, facts, or insights discovered during research.")]
    public string SaveNote(
        [Description("A short descriptive title for the note.")] string title,
        [Description("The content of the note — facts, quotes, or analysis.")] string content,
        [Description("The source URL where this information was found, if applicable.")] string? sourceUrl = null)
    {
        var note = new Note(title, content, sourceUrl);
        _notes.Add(note);
        return $"Note saved: \"{title}\" (total notes: {_notes.Count})";
    }

    [AIFunction(Name = "get_notes")]
    [Description("Retrieves all saved research notes. Use this to review what has been collected before writing a summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes saved yet. Use save_note to record findings.";
        }

        var entries = _notes.Select((n, i) =>
        {
            var source = n.SourceUrl is not null ? $"\n   Source: {n.SourceUrl}" : "";
            return $"[{i + 1}] {n.Title}{source}\n   {n.Content}";
        });

        return $"=== Research Notes ({_notes.Count} total) ===\n\n{string.Join("\n\n", entries)}";
    }

    private sealed record Note(string Title, string Content, string? SourceUrl);
}

