        var snippetMatches = Regex.Matches(html, @"<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>", RegexOptions.Singleline);

        for (var i = 0; i < Math.Min(linkMatches.Count, 8); i++)
        {
            var title = StripHtml(linkMatches[i].Groups[2].Value).Trim();
            var link = linkMatches[i].Groups[1].Value.Trim();

            // DuckDuckGo wraps URLs in a redirect; extract the actual URL
            var uddgMatch = Regex.Match(link, @"uddg=([^&]+)");
            if (uddgMatch.Success)
            {
                link = Uri.UnescapeDataString(uddgMatch.Groups[1].Value);
            }

            var snippet = i < snippetMatches.Count
                ? StripHtml(snippetMatches[i].Groups[1].Value).Trim()
                : "";

            results.Add($"[{i + 1}] {title}\n    URL: {link}\n    {snippet}");
        }

        return results.Count > 0
            ? string.Join("\n\n", results)
            : "No results found. Try rephrasing your query.";
    }

    private static string ExtractTextFromHtml(string html)
    {
        // Remove script and style blocks
        var cleaned = Regex.Replace(html, @"<(script|style|nav|header|footer)[^>]*>.*?</\1>", "", RegexOptions.Singleline | RegexOptions.IgnoreCase);

        // Decode common entities
        cleaned = cleaned
            .Replace("&amp;", "&")
            .Replace("&lt;", "<")
            .Replace("&gt;", ">")
            .Replace("&quot;", "\"")
            .Replace("&#39;", "'")
            .Replace("&nbsp;", " ");

        // Add line breaks for block elements
        cleaned = Regex.Replace(cleaned, @"<(br|p|div|h[1-6]|li|tr)[^>]*>", "\n", RegexOptions.IgnoreCase);

        // Strip remaining HTML tags
        cleaned = HtmlTagRegex().Replace(cleaned, "");

        // Collapse whitespace
        cleaned = WhitespaceRegex().Replace(cleaned, " ");

        // Collapse multiple newlines
        cleaned = Regex.Replace(cleaned, @"\n{3,}", "\n\n");

        return cleaned.Trim();
    }

    private static string StripHtml(string html)
    {
        var text = html
            .Replace("&amp;", "&")
            .Replace("&lt;", "<")
            .Replace("&gt;", ">")
            .Replace("&quot;", "\"")
            .Replace("&#39;", "'")
            .Replace("<b>", "")
            .Replace("</b>", "");

        return HtmlTagRegex().Replace(text, "");
    }
}

